export const mfgCss = "@font-face{font-family:'S-Core Dream';src:url('/fonts/scdream-6.woff2') format('woff2');font-weight:600;font-display:swap}\n@font-face{font-family:'S-Core Dream';src:url('/fonts/scdream-8.woff2') format('woff2');font-weight:800;font-display:swap}\n@font-face{font-family:'Freesentation';src:url('/fonts/freesentation-4.woff2') format('woff2');font-weight:400;font-display:swap}\n@font-face{font-family:'Freesentation';src:url('/fonts/freesentation-6.woff2') format('woff2');font-weight:600;font-display:swap}\n@font-face{font-family:'Freesentation';src:url('/fonts/freesentation-7.woff2') format('woff2');font-weight:700;font-display:swap}\n.mfg{\n  --bg:#F4F6F1; --ink:#10241D; --dark:#0F2A22; --panel:#123B2E;\n  --pine:#1D6A50; --ok:#2E9E68; --warn:#E8A33A; --risk:#D4553F;\n  --lime:#CDEA6A; --cyan:#5CC3B0; --muted:#5C7168; --line:#DCE3DA; --card:#FFFFFF; --r:24px;\n}\n.mfg *{margin:0;padding:0;box-sizing:border-box}\n.mfg{scroll-behavior:smooth}\n.mfg{font-family:'Noto Sans KR',-apple-system,sans-serif;background:var(--bg);color:var(--ink);line-height:1.6;-webkit-font-smoothing:antialiased}\n.mfg .mono{font-family:'Space Grotesk','Noto Sans KR',sans-serif}\n.mfg .wrap{max-width:1180px;margin:0 auto;padding:0 28px}\n.mfg .eyebrow{font-size:12px;font-weight:900;letter-spacing:.22em;color:var(--pine);text-transform:uppercase;margin-bottom:14px}\n.mfg section{padding:84px 0}\n.mfg /* nav */\nnav{position:sticky;top:0;z-index:50;background:rgba(244,246,241,.85);backdrop-filter:blur(12px);border-bottom:1px solid var(--line)}\n.mfg .nav-in{max-width:1180px;margin:0 auto;padding:14px 28px;display:flex;align-items:center;gap:22px}\n.mfg .logo{font-weight:900;font-size:17px}\n.mfg .logo small{font-weight:500;color:var(--muted);font-size:12px;margin-left:8px}\n.mfg .nav-badge{font-size:11px;font-weight:900;color:var(--pine);border:1.5px solid var(--pine);border-radius:999px;padding:4px 11px;letter-spacing:.02em}\n.mfg .nav-links{display:flex;gap:20px;margin-left:auto}\n.mfg .nav-links a{font-size:13.5px;font-weight:700;color:var(--ink);text-decoration:none}\n.mfg .nav-links a:hover{color:var(--pine)}\n.mfg .live{display:flex;align-items:center;gap:7px;font-size:12px;font-weight:700;color:var(--muted)}\n.mfg .live .dot{width:8px;height:8px;border-radius:50%;background:var(--risk);animation:blink 1.6s infinite}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:.35}}\n.mfg .btn{display:inline-block;background:var(--dark);color:#fff;text-decoration:none;font-size:13.5px;font-weight:900;padding:11px 22px;border-radius:999px;transition:.15s}\n.mfg .btn:hover{background:var(--pine);transform:translateY(-1px)}\n.mfg .btn.ghost{background:transparent;color:var(--ink);border:1.5px solid var(--ink)}\n.mfg .btn.ghost:hover{background:var(--ink);color:#fff}\n.mfg .btn.lime{background:var(--lime);color:var(--ink)}\n.mfg .btn.lime:hover{background:#fff}\n@media (prefers-reduced-motion:reduce){.mfg .live .dot, .mfg .tick-track, .mfg .chip{animation:none!important}}\n.mfg /* hero — 회사소개·헬스케어와 같은 브랜드 타이포/색상 규칙 */\n.hero{padding:52px 0 38px;background:#fff;color:#17232E;font-family:'Freesentation',sans-serif}\n.mfg .hero-grid{display:grid;grid-template-columns:minmax(0,1.02fr) minmax(0,.98fr);gap:52px;align-items:center}\n.mfg .hero .eyebrow{font-size:16px;line-height:1.5;letter-spacing:.16em;color:#0B3FD8;margin-bottom:16px}\n.mfg .hero h1{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:clamp(40px,3.7vw,50px);font-weight:800;line-height:1.18;letter-spacing:-.035em;color:#17232E}\n.mfg .hero h1 .hl{color:#0B3FD8}\n.mfg .hero p.sub{margin:28px 0 0;font-size:19px;line-height:1.72;color:#3A4956;max-width:590px;font-weight:600}\n.mfg .hero p.sub + p.sub-detail{margin-top:14px}\n.mfg .hero p.sub-detail{font-size:16.5px;line-height:1.78;color:#526170;max-width:590px}\n.mfg .hero p.sub b, .mfg .hero p.sub-detail b{color:#17232E;font-weight:700}\n.mfg .cta-row{display:flex;gap:12px;flex-wrap:wrap}\n.mfg .hero .cta-row{margin-top:26px}\n.mfg .hero .btn{background:#17232E;padding:12px 23px;font-size:14px}\n.mfg .hero .btn:hover{background:#0B3FD8}\n.mfg .hero .btn.ghost{background:#fff;color:#17232E;border-color:#B9C5D1}\n.mfg .hero .btn.ghost:hover{background:#F2F6FF;color:#0B3FD8;border-color:#0B3FD8}\n.mfg .hero .hero-status{display:inline-flex;align-items:center;font-size:14px;font-weight:600;color:#526170}\n.mfg .hero .hero-status::before{content:\"\";width:7px;height:7px;border-radius:50%;background:#0B3FD8;margin-right:8px}\n.mfg .hero-visual{position:relative}\n.mfg .hero-visual .screen{background:#10243A;border-radius:24px;padding:12px;box-shadow:0 28px 64px rgba(23,35,46,.22)}\n.mfg /* dashboard svg card */\n.screen{background:var(--dark);border-radius:var(--r);padding:14px;box-shadow:0 30px 70px rgba(16,36,29,.28)}\n.mfg .screen svg{width:100%;height:auto;display:block;border-radius:14px}\n.mfg /* deck slide card (사용자 발표자료 이미지) */\n.deck{background:#fff;border:1px solid var(--line);border-radius:18px;padding:10px;box-shadow:0 18px 44px rgba(16,36,29,.12);overflow:hidden}\n.mfg .deck img{width:100%;height:auto;display:block;border-radius:10px}\n.mfg .deck.frame-dark{background:var(--dark);border-color:var(--dark);box-shadow:0 24px 60px rgba(16,36,29,.28)}\n.mfg .deck-cap{font-size:11.5px;color:var(--muted);margin-top:8px;padding:0 4px 2px;text-align:center}\n.mfg .deck.frame-dark + .deck-cap{color:#8FD3B4}\n.mfg /* ticker */\n.ticker{border-top:1px solid #CCD8E8;border-bottom:1px solid #CCD8E8;overflow:hidden;background:#EEF4FF;padding:11px 0;font-family:'Freesentation',sans-serif}\n.mfg .tick-track{display:flex;width:max-content;animation:scroll 30s linear infinite}\n@keyframes scroll{to{transform:translateX(-50%)}}\n.mfg .tick-item{display:flex;align-items:center;padding:0 24px;font-size:14px;font-weight:700;color:#294057;white-space:nowrap}\n.mfg .tick-item::after{content:\"◆\";font-size:7px;margin-left:24px;color:#0B3FD8;opacity:.65}\n.mfg /* 03 · 제조현장의 문제와 전환 */\n.ax-transition{background:#FFFFFF;font-family:'Freesentation',sans-serif}\n.mfg .ax-transition .trans-head{max-width:940px;margin-bottom:30px}\n.mfg .ax-transition .eyebrow{font-size:16px;line-height:1.5;letter-spacing:.16em;color:#0B3FD8;margin-bottom:16px}\n.mfg .ax-transition .trans-head h2{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:clamp(34px,4vw,48px);font-weight:800;letter-spacing:-.035em;line-height:1.24;color:#17232E}\n.mfg .ax-transition .trans-lead{font-size:17.5px;line-height:1.72;color:#3A4956;font-weight:600;margin-top:22px;max-width:900px}\n.mfg .transition-table{border:1px solid #D8E1EB;border-radius:22px;overflow:hidden;background:#FFFFFF;box-shadow:0 14px 36px rgba(23,35,46,.06)}\n.mfg .transition-labels{display:grid;grid-template-columns:minmax(0,1fr) 62px minmax(0,1fr);align-items:center;background:#F4F7FB;border-bottom:1px solid #D8E1EB}\n.mfg .transition-label{padding:12px 22px;font-size:12px;font-weight:700;letter-spacing:.13em}\n.mfg .transition-label.as{color:#8A5A32}\n.mfg .transition-label.to{color:#0B3FD8}\n.mfg .transition-row{display:grid;grid-template-columns:minmax(0,1fr) 62px minmax(0,1fr);align-items:stretch;border-bottom:1px solid #E1E7EE}\n.mfg .transition-row:last-child{border-bottom:0}\n.mfg .transition-cell{padding:18px 22px}\n.mfg .transition-cell.pain{background:#FAFBFC}\n.mfg .transition-cell.solution{background:#FFFFFF}\n.mfg .transition-cell .module{display:inline-flex;align-items:center;font-size:11px;font-weight:700;letter-spacing:.08em;color:#0B3FD8;margin-bottom:7px}\n.mfg .transition-cell .module::before{content:\"\";width:6px;height:6px;border-radius:50%;background:#00CFF0;margin-right:7px}\n.mfg .transition-cell h3{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:20px;line-height:1.4;font-weight:800;letter-spacing:-.02em;color:#17232E}\n.mfg .transition-cell.pain h3{color:#354452}\n.mfg .transition-cell p{font-size:14.5px;line-height:1.68;color:#526170;margin-top:6px}\n.mfg .transition-arrow{display:flex;align-items:center;justify-content:center;background:#EEF4FF;color:#0B3FD8;font-size:22px;font-weight:700}\n.mfg .transition-core{display:flex;align-items:center;justify-content:center;gap:12px;margin-top:20px;font-size:13.5px;font-weight:700;color:#294057}\n.mfg .transition-core span{border:1px solid #C8D5E3;border-radius:999px;background:#F7FAFF;padding:7px 14px}\n.mfg .transition-core b{color:#0B3FD8;font-size:16px}\n.mfg /* features */\n#capabilities .head{max-width:640px;margin-bottom:52px}\n.mfg #capabilities h2{font-size:clamp(26px,3.4vw,40px);font-weight:900;letter-spacing:-.02em;line-height:1.25}\n.mfg .feature{display:grid;grid-template-columns:1fr 1.15fr;gap:44px;align-items:center;padding:46px 0;border-top:1px solid var(--line)}\n.mfg .feature.flip{grid-template-columns:1.15fr 1fr}\n.mfg .feature.flip .f-media{order:-1}\n.mfg .f-num{font-family:'Space Grotesk',sans-serif;font-size:13px;font-weight:700;color:var(--pine);letter-spacing:.14em;margin-bottom:10px}\n.mfg .f-text h3{font-size:clamp(21px,2.5vw,29px);font-weight:900;letter-spacing:-.015em;margin-bottom:12px}\n.mfg .f-text p{font-size:14.5px;color:var(--muted);max-width:460px}\n.mfg .f-text p b{color:var(--ink)}\n.mfg .f-tags{display:flex;gap:8px;flex-wrap:wrap;margin-top:18px}\n.mfg .f-tag{font-size:12px;font-weight:700;border:1.5px solid var(--ink);border-radius:999px;padding:5px 13px}\n.mfg .f-media .screen{padding:12px}\n.mfg /* 04 · Manufacturing AI Pack */\n#capabilities:has(.mfg-ai-head){background:#FFFFFF;font-family:'Freesentation',sans-serif}\n.mfg .mfg-ai-head{max-width:940px!important;margin-bottom:24px!important;font-family:'Freesentation',sans-serif}\n.mfg .mfg-ai-head .eyebrow{font-size:16px;line-height:1.5;letter-spacing:.16em;color:#0B3FD8;margin-bottom:16px}\n.mfg #capabilities .mfg-ai-head h2{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:clamp(34px,4vw,48px);font-weight:800;letter-spacing:-.035em;line-height:1.24;color:#17232E}\n.mfg .mfg-ai-head .head-lead{font-size:17.5px;line-height:1.72;color:#3A4956;font-weight:600;margin-top:22px;max-width:900px}\n.mfg .mfg-ai-head .head-status{display:inline-flex;align-items:center;margin-top:14px;font-size:13.5px;font-weight:600;color:#526170}\n.mfg .mfg-ai-head .head-status::before{content:\"\";width:7px;height:7px;border-radius:50%;background:#0B3FD8;margin-right:8px}\n.mfg .mfg-ai-detail{grid-template-columns:minmax(0,.9fr) minmax(0,1.1fr);gap:30px;padding:18px 0 0;border-top:0}\n.mfg .mfg-ai-phases{display:grid;gap:12px}\n.mfg .mfg-ai-phase{background:#F7F9FC;border:1px solid #D8E1EB;border-radius:18px;padding:20px}\n.mfg .mfg-ai-phase.active{background:#EDF3FF;border-color:#BFD0E7}\n.mfg .mfg-ai-phase .phase-label{font-size:12px;font-weight:700;letter-spacing:.11em;color:#0B3FD8;margin-bottom:8px}\n.mfg .mfg-ai-phase h3{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:21px;line-height:1.4;font-weight:800;letter-spacing:-.02em;color:#17232E}\n.mfg .mfg-ai-phase p{font-size:14.5px;line-height:1.68;color:#526170;margin-top:7px}\n.mfg .mfg-ai-phase .phase-points{display:flex;gap:7px;flex-wrap:wrap;margin-top:13px}\n.mfg .mfg-ai-phase .phase-points span{font-size:11.5px;font-weight:700;color:#294057;border:1px solid #C8D5E3;border-radius:999px;background:#FFFFFF;padding:4px 9px}\n.mfg .mfg-ai-visual .screen{background:#10243A;border-radius:22px;padding:12px;box-shadow:0 22px 54px rgba(23,35,46,.18)}\n.mfg /* 05 · 국제표준 연동 Pack */\n#capabilities:has(.standard-integration){background:#F7F9FC;font-family:'Freesentation',sans-serif}\n.mfg .standard-integration{grid-template-columns:minmax(0,.94fr) minmax(0,1.06fr);gap:38px;padding:0;border-top:0}\n.mfg .standard-copy .eyebrow{font-size:16px;line-height:1.5;letter-spacing:.16em;color:#0B3FD8;margin-bottom:16px}\n.mfg #capabilities .standard-copy h2{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:clamp(34px,3.3vw,42px);font-weight:800;letter-spacing:-.035em;line-height:1.24;color:#17232E}\n.mfg .standard-copy .standard-lead{font-size:17px;line-height:1.72;color:#3A4956;font-weight:600;margin-top:22px;max-width:530px}\n.mfg .standard-copy .standard-status{display:inline-flex;align-items:center;margin-top:14px;font-size:13.5px;font-weight:600;color:#526170}\n.mfg .standard-copy .standard-status::before{content:\"\";width:7px;height:7px;border-radius:50%;background:#0B3FD8;margin-right:8px}\n.mfg .standard-phases{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:24px}\n.mfg .standard-phase{border:1px solid #D4DFEB;border-radius:15px;background:#FFFFFF;padding:15px 16px}\n.mfg .standard-phase .phase-label{font-size:11.5px;font-weight:700;letter-spacing:.08em;color:#0B3FD8}\n.mfg .standard-phase b{display:block;font-family:'S-Core Dream','Freesentation',sans-serif;font-size:15px;line-height:1.45;color:#17232E;margin-top:6px}\n.mfg .standard-phase p{font-size:12.5px;line-height:1.55;color:#62717E;margin-top:5px}\n.mfg .standard-visual .screen{background:#10243A;border-radius:22px;padding:12px;box-shadow:0 22px 54px rgba(23,35,46,.18)}\n.mfg /* 06 · Roll-out Kit */\n#capabilities:has(.rollout-kit){background:#FFFFFF;font-family:'Freesentation',sans-serif;padding:44px 0}\n.mfg .rollout-kit{display:block;padding:0;border-top:0}\n.mfg .rollout-head{max-width:1000px}\n.mfg .rollout-head .eyebrow{font-size:16px;line-height:1.5;letter-spacing:.16em;color:#0B3FD8;margin-bottom:16px}\n.mfg #capabilities .rollout-head h2{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:clamp(34px,4vw,48px);font-weight:800;letter-spacing:-.035em;line-height:1.24;color:#17232E}\n.mfg .rollout-head .rollout-lead{font-size:17.5px;line-height:1.72;color:#3A4956;font-weight:600;margin-top:20px;max-width:920px}\n.mfg .rollout-head .rollout-status{display:inline-flex;align-items:center;margin-top:12px;font-size:13.5px;font-weight:600;color:#526170}\n.mfg .rollout-head .rollout-status::before{content:\"\";width:7px;height:7px;border-radius:50%;background:#0B3FD8;margin-right:8px}\n.mfg .rollout-body{display:grid;grid-template-columns:minmax(0,.88fr) minmax(0,1.12fr);gap:30px;align-items:center;margin-top:24px}\n.mfg .rollout-stages{display:grid;gap:9px}\n.mfg .rollout-stage{display:grid;grid-template-columns:42px 1fr;gap:13px;align-items:center;border:1px solid #D7E1EC;border-radius:15px;background:#F7F9FC;padding:13px 15px}\n.mfg .rollout-stage .stage-num{display:flex;align-items:center;justify-content:center;width:42px;height:42px;border-radius:12px;background:#EDF3FF;color:#0B3FD8;font-size:12px;font-weight:700;letter-spacing:.05em}\n.mfg .rollout-stage b{display:block;font-family:'S-Core Dream','Freesentation',sans-serif;font-size:16px;line-height:1.4;color:#17232E}\n.mfg .rollout-stage p{font-size:13px;line-height:1.55;color:#62717E;margin-top:3px}\n.mfg .rollout-visual .screen{background:#10243A;border-radius:22px;padding:12px;box-shadow:0 22px 54px rgba(23,35,46,.18)}\n.mfg /* 3개 추진 영역 요약 */\n.responsibility-summary{background:#F7F9FC;font-family:'Freesentation',sans-serif}\n.mfg .responsibility-summary .summary-head{max-width:880px;margin-bottom:34px}\n.mfg .responsibility-summary .eyebrow{font-size:16px;line-height:1.5;letter-spacing:.16em;color:#0B3FD8;margin-bottom:16px}\n.mfg .responsibility-summary h2{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:clamp(34px,4vw,48px);font-weight:800;letter-spacing:-.035em;line-height:1.24;color:#17232E}\n.mfg .responsibility-summary .summary-lead{font-size:18px;line-height:1.72;color:#3A4956;font-weight:600;margin-top:24px;max-width:820px}\n.mfg .responsibility-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}\n.mfg .responsibility-card{position:relative;display:flex;flex-direction:column;min-height:304px;background:#fff;border:1px solid #D9E2EC;border-radius:22px;padding:28px 26px;box-shadow:0 12px 30px rgba(23,35,46,.06)}\n.mfg .responsibility-card::before{content:\"\";position:absolute;left:26px;right:26px;top:0;height:4px;border-radius:0 0 4px 4px;background:linear-gradient(90deg,#0B3FD8,#00CFF0)}\n.mfg .responsibility-card .card-num{font-size:13px;line-height:1.5;font-weight:700;letter-spacing:.11em;color:#0B3FD8;margin-bottom:16px}\n.mfg .responsibility-card h3{font-family:'S-Core Dream','Freesentation',sans-serif;font-size:23px;line-height:1.38;font-weight:800;letter-spacing:-.025em;color:#17232E}\n.mfg .responsibility-card p{font-size:16px;line-height:1.72;color:#526170;margin-top:14px}\n.mfg .responsibility-card .f-tags{margin-top:auto;padding-top:20px}\n.mfg .responsibility-card .f-tag{font-size:12px;color:#294057;border-color:#C8D5E3;background:#F7FAFF;padding:5px 10px}\n.mfg .summary-foot{display:flex;align-items:center;justify-content:space-between;gap:20px;margin-top:22px;padding:17px 20px;border:1px solid #D7E1EE;border-radius:14px;background:#EDF3FF;color:#294057;font-size:14px}\n.mfg .summary-foot b{color:#0B3FD8}\n.mfg /* consortium */\n.consortium{display:grid;grid-template-columns:repeat(5,1fr);gap:12px}\n.mfg .org{background:var(--card);border:1px solid var(--line);border-radius:16px;padding:18px 16px}\n.mfg .org.us{border:2px solid var(--pine);background:#F2F8F2}\n.mfg .org .role{font-size:11px;font-weight:900;letter-spacing:.06em;color:var(--pine);margin-bottom:7px}\n.mfg .org h4{font-size:15px;font-weight:900;letter-spacing:-.01em}\n.mfg .org .desc{font-size:12px;color:var(--muted);margin-top:5px;line-height:1.5}\n.mfg .org .badge-us{display:inline-block;margin-top:9px;font-size:10.5px;font-weight:900;background:var(--lime);color:var(--ink);border-radius:6px;padding:2px 8px}\n.mfg /* stats */\n.stats-band{background:var(--dark);color:#fff}\n.mfg .stats-band .eyebrow{color:var(--lime)}\n.mfg .stats-band h2{font-size:clamp(24px,3.2vw,36px);font-weight:900;letter-spacing:-.02em;margin-bottom:40px;line-height:1.3}\n.mfg .stat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,.14);border-radius:18px;overflow:hidden}\n.mfg .stat{background:var(--dark);padding:26px 22px}\n.mfg .stat .v{font-family:'Space Grotesk','Noto Sans KR',sans-serif;font-size:34px;font-weight:700;color:var(--lime);line-height:1.1}\n.mfg .stat .v small{font-size:17px}\n.mfg .stat .k{font-size:12.5px;color:#AFC5BB;margin-top:8px}\n.mfg .stat .note{font-size:10.5px;color:#7E958B;margin-top:3px}\n.mfg /* roadmap */\n.stage-row{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-top:8px}\n.mfg .stage{background:var(--card);border:1px solid var(--line);border-radius:18px;padding:22px 22px;position:relative}\n.mfg .stage.now{border-color:var(--pine);border-width:1.5px}\n.mfg .stage .idx{font-family:'Space Grotesk',sans-serif;font-size:12px;font-weight:700;letter-spacing:.12em;color:var(--pine)}\n.mfg .stage h3{font-size:19px;font-weight:900;margin:6px 0 4px;letter-spacing:-.01em}\n.mfg .stage .when{font-size:12px;font-weight:700;color:var(--muted);margin-bottom:12px}\n.mfg .stage ul{list-style:none}\n.mfg .stage li{font-size:13px;color:var(--ink);padding:5px 0 5px 16px;position:relative}\n.mfg .stage li::before{content:\"\";position:absolute;left:2px;top:12px;width:6px;height:6px;border-radius:50%;background:var(--pine)}\n.mfg .stage .tag{position:absolute;top:18px;right:18px;font-size:10px;font-weight:900;border-radius:6px;padding:2px 8px}\n.mfg .stage.now .tag{background:var(--lime);color:var(--ink)}\n.mfg .stage:not(.now) .tag{background:#EEF1EC;color:var(--muted)}\n.mfg .flowline{display:flex;align-items:center;gap:10px;margin-top:26px;flex-wrap:wrap;font-size:13.5px;font-weight:800;color:var(--ink)}\n.mfg .flowline .node{background:var(--card);border:1px solid var(--line);border-radius:999px;padding:8px 16px}\n.mfg .flowline .node.hi{background:var(--dark);color:#fff}\n.mfg .flowline .ar{color:var(--pine);font-weight:900}\n.mfg /* cta */\n.cta-band{background:var(--dark);border-radius:28px;padding:60px 48px;color:#fff;text-align:center}\n.mfg .cta-band h2{font-size:clamp(25px,3.4vw,38px);font-weight:900;letter-spacing:-.02em;line-height:1.3}\n.mfg .cta-band p{color:#C7DCD2;margin:14px 0 26px;font-size:15px}\n.mfg footer{padding:34px 0 44px;font-size:12px;color:var(--muted)}\n.mfg .foot-in{display:flex;justify-content:space-between;gap:16px;flex-wrap:wrap}\n.mfg .disc{font-size:11px;color:#93A79D;margin-top:8px;max-width:900px}\n@media(max-width:920px){.mfg section{padding:60px 0}.mfg .nav-links, .mfg .live, .mfg .nav-badge{display:none}.mfg .hero-grid{grid-template-columns:1fr}.mfg .hero p.sub{font-size:18px}.mfg .ax-transition .trans-head{margin-bottom:24px}.mfg .ax-transition .trans-head h2{font-size:36px}.mfg .ax-transition .trans-lead{font-size:16px;margin-top:18px}.mfg .transition-labels, .mfg .transition-row{grid-template-columns:minmax(0,1fr) 48px minmax(0,1fr)}.mfg .transition-label{padding:10px 16px}.mfg .transition-cell{padding:16px}.mfg .transition-cell h3{font-size:18px}.mfg .transition-cell p{font-size:13.5px}.mfg .feature, .mfg .feature.flip{grid-template-columns:1fr;gap:24px}.mfg .feature.flip .f-media{order:0}.mfg .mfg-ai-head{margin-bottom:20px!important}.mfg #capabilities .mfg-ai-head h2{font-size:36px}.mfg .mfg-ai-head .head-lead{font-size:16px;margin-top:18px}.mfg .mfg-ai-detail{grid-template-columns:minmax(0,.9fr) minmax(0,1.1fr);gap:18px;padding-top:12px}.mfg .mfg-ai-phase{padding:16px}.mfg .mfg-ai-phase h3{font-size:18px}.mfg .mfg-ai-phase p{font-size:13.5px}.mfg .standard-integration{grid-template-columns:minmax(0,.92fr) minmax(0,1.08fr);gap:22px}.mfg #capabilities .standard-copy h2{font-size:34px}.mfg .standard-copy .standard-lead{font-size:15.5px;margin-top:18px}.mfg .standard-phases{grid-template-columns:1fr;gap:8px;margin-top:18px}.mfg .standard-phase{padding:12px 14px}.mfg #capabilities .rollout-head h2{font-size:36px}.mfg .rollout-head .rollout-lead{font-size:16px;margin-top:18px}.mfg .rollout-body{grid-template-columns:minmax(0,.86fr) minmax(0,1.14fr);gap:20px;margin-top:18px}.mfg .rollout-stage{padding:11px 12px}.mfg .rollout-stage p{font-size:12.5px}.mfg .responsibility-summary .summary-head{margin-bottom:26px}.mfg .responsibility-summary h2{font-size:36px}.mfg .responsibility-summary .summary-lead{font-size:16.5px;margin-top:18px}.mfg .responsibility-grid{gap:12px}.mfg .responsibility-card{min-height:330px;padding:24px 20px}.mfg .responsibility-card::before{left:20px;right:20px}.mfg .responsibility-card h3{font-size:20px}.mfg .responsibility-card p{font-size:14.5px}.mfg .responsibility-card .f-tag{font-size:11px;padding:4px 8px}.mfg .summary-foot{font-size:13px}.mfg .consortium{grid-template-columns:1fr 1fr}.mfg .stat-grid{grid-template-columns:1fr}.mfg .stage-row{grid-template-columns:1fr}.mfg .cta-band{padding:44px 24px}}\n@media(max-width:700px){.mfg .hero .wide-break{display:none}.mfg .ax-transition .wide-break{display:none}.mfg .transition-labels{display:none}.mfg .transition-row{grid-template-columns:1fr}.mfg .transition-cell{padding:20px}.mfg .transition-arrow{min-height:38px;transform:none}.mfg .transition-arrow span{transform:rotate(90deg)}.mfg .transition-core{align-items:stretch;flex-direction:column;text-align:center}.mfg .transition-core b{transform:rotate(90deg)}.mfg .mfg-ai-detail{grid-template-columns:1fr}.mfg .standard-integration{grid-template-columns:1fr}.mfg #capabilities:has(.standard-integration){padding:44px 0}.mfg #capabilities:has(.rollout-kit){padding:44px 0}.mfg #capabilities .rollout-head h2{font-size:32px}.mfg .rollout-body{grid-template-columns:1fr}.mfg .rollout-stage{padding:8px 12px}.mfg .rollout-stage p{display:none}.mfg .responsibility-grid{grid-template-columns:1fr}.mfg .responsibility-card{min-height:0}.mfg .summary-foot{align-items:flex-start;flex-direction:column}}";

